const loginForm=document.getElementById("login-form"),loginButton=document.getElementById("login-button"),loginMessage=document.getElementById("login-message"),loginInput=document.getElementById("id_magalu"),existingSession=window.magaluApi.readStoredUser();function setMessage(e,t){loginMessage.textContent=e,loginMessage.className=`form-message ${t}`}existingSession&&window.location.replace(window.magaluApi.getAuthenticatedHomeUrl(existingSession)),loginForm.addEventListener("submit",async e=>{e.preventDefault();const t=loginInput.value.trim();if(t){loginButton.disabled=!0,loginButton.setAttribute("aria-busy","true"),setMessage("","");try{const e=await fetch(window.magaluApi.buildApiUrl("/api/auth/login"),window.magaluApi.withApiDefaults({method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({id_magalu:t})})),o=await e.json();if(!e.ok)throw new Error(o.error||"Nao foi possivel efetuar o login.");window.magaluApi.storeUser(o.user),setMessage("Login efetuado. Redirecionando...","success"),window.setTimeout(()=>{window.location.href=window.magaluApi.getAuthenticatedHomeUrl(o.user)},400)}catch(e){setMessage(e.message,"error")}finally{loginButton.disabled=!1,loginButton.removeAttribute("aria-busy")}}else setMessage("Informe o ID Magalu para entrar.","error")});